input.command:
cd /tmp
dpkg-query -f '${binary:Package}\n' -W 2>/dev/null | sed 's/:.*//' | sort -u > /tmp/pkgs.txt
apt-cache policy $(cat /tmp/pkgs.txt | tr '\n' ' ') 2>/dev/null | awk '
/^[a-zA-Z0-9]/ {pkg=$0; sub(":$","",pkg); localonly=1; inst=""}
/Installed:/ {inst=$2}
/^ *[0-9]+ (http|https|file|cdrom)/ {localonly=0}
/^$/ {}
{ }
END{}
' > /dev/null
# simpler: per-package check for packages with no remote origin
python3 - <<'EOF'
import subprocess
pkgs=open('/tmp/pkgs.txt').read().split()
out=subprocess.run(['apt-cache','policy']+pkgs,capture_output=True,text=True).stdout
cur=None;remote=False;inst=None;local=[]
for line in out.splitlines():
    if line and not line.startswith(' '):
        if cur and inst and inst!='(none)' and not remote: local.append((cur,inst))
        cur=line.rstrip(':');remote=False;inst=None
    elif line.strip().startswith('Installed:'): inst=line.split()[-1]
    elif line.strip().startswith(('http','https')) or '://' in line: remote=True
    elif line.strip() and line.strip()[0].isdigit() and 'dpkg/status' not in line: remote=True
if cur and inst and inst!='(none)' and not remote: local.append((cur,inst))
print(f"packages with no remote repo candidate: {len(local)}")
for p,v in local: print(" ",p,v)
EOF

